import { Linking } from 'react-native';
import { NavigationActions, StackActions } from '@react-navigation/native';

const handleDeepLink = (url) => {
  const urlParts = url.split('/');
  const scheme = urlParts[0];
  const screenName = urlParts[1];

  if (scheme === 'myapp') {
    switch (screenName) {
      case 'profile':
        return navigateToProfile(urlParts);
      case 'payment':
        return navigateToPayment(urlParts);
      default:
        return false;
    }
  }

  return false;
};

const navigateToProfile = (urlParts) => {
  const userId = urlParts[2];
  const params = { userId };
  return NavigationActions.navigate({ routeName: 'Profile', params });
};

const navigateToPayment = (urlParts) => {
  const paymentId = urlParts[3];
  const params = { paymentId };
  return StackActions.replace('Payment', params);
};

Linking.addEventListener('url', (event) => {
  if (!handleDeepLink(event.url)) {
    Linking.openURL(event.url);
  }
});